import { useCallback, useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { getSales, getSalesStats, deleteSale } from "../../api/saleApi";
import { getAuth } from "../../utils/auth";

const monthName = (m) =>
  ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"][m - 1];

export default function SaleList() {
  const [sales, setSales] = useState([]);
  const [stats, setStats] = useState(null);

  const [loading, setLoading] = useState(false);
  const [statsLoading, setStatsLoading] = useState(false);

  const [error, setError] = useState("");

  const navigate = useNavigate();
  const { role } = getAuth();

  const canManage = role === "admin" || role === "manager";
  const year = new Date().getFullYear();

  // ✅ Load sales + stats (stats is optional)
  const load = useCallback(async () => {
    setError("");
    setLoading(true);

    try {
      const salesRes = await getSales();
      setSales(salesRes.data || []);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to load sales");
    } finally {
      setLoading(false);
    }

    // stats should NOT block showing the list
    setStatsLoading(true);
    try {
      const statsRes = await getSalesStats(year);
      setStats(statsRes.data);
    } catch (err) {
      // If stats route not working, just ignore and fallback to totalsFromList
      setStats(null);
    } finally {
      setStatsLoading(false);
    }
  }, [year]);

  useEffect(() => {
    load();
  }, [load]);

  // ✅ fallback totals (if stats is null)
  const totalsFromList = useMemo(() => {
    const completed = sales.filter((s) => s.dealStatus === "completed");
    const totalRevenue = completed.reduce((sum, s) => {
      const revenue = s.finalPrice ?? s.quotedPrice ?? 0;
      return sum + Number(revenue);
    }, 0);

    const months = {};
    completed.forEach((s) => {
      const d = new Date(s.createdAt);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
      months[key] = (months[key] || 0) + Number(s.finalPrice ?? s.quotedPrice ?? 0);
    });

    const monthlyAvg = Object.keys(months).length
      ? totalRevenue / Object.keys(months).length
      : 0;

    return {
      completedCount: completed.length,
      totalRevenue,
      avgMonthlyRevenue: monthlyAvg,
    };
  }, [sales]);

  const totalRevenue = stats?.totalRevenue ?? totalsFromList.totalRevenue;
  const totalSales = stats?.totalSales ?? totalsFromList.completedCount;
  const avgMonthlyRevenue = stats?.avgMonthlyRevenue ?? totalsFromList.avgMonthlyRevenue;

  const onDelete = async (id) => {
    if (!canManage) return alert("Access denied");
    if (!window.confirm("Delete this sale record?")) return;

    try {
      await deleteSale(id);
      alert("Deleted");
      await load();
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  return (
    <div style={{ padding: 20 }}>
      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <h2 style={{ margin: 0 }}>Sales Transactions</h2>

        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={load} disabled={loading}>
            {loading ? "Loading..." : "Refresh"}
          </button>

          {canManage && (
            <Link to="/sales/add">
              <button>+ Add Sale</button>
            </Link>
          )}
        </div>
      </div>

      {/* Error */}
      {error && (
        <div style={{ marginTop: 12, padding: 10, border: "1px solid #fca5a5", borderRadius: 8 }}>
          <b>Error:</b> {error}
        </div>
      )}

      {/* Stats */}
      <div style={{ marginTop: 14, border: "1px solid #ddd", borderRadius: 10, padding: 14 }}>
        <div style={{ display: "flex", gap: 20, flexWrap: "wrap" }}>
          <div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Total Completed Revenue ({year})</div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>
              Rs. {Number(totalRevenue || 0).toLocaleString()}
            </div>
          </div>

          <div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Completed Sales Count</div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>{Number(totalSales || 0)}</div>
          </div>

          <div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Average Monthly Revenue</div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>
              Rs. {Number(avgMonthlyRevenue || 0).toLocaleString()}
            </div>
          </div>

          {stats?.bestMonth && (
            <div>
              <div style={{ fontSize: 12, opacity: 0.7 }}>Best Month</div>
              <div style={{ fontSize: 22, fontWeight: 700 }}>
                {monthName(stats.bestMonth.month)} — Rs.{" "}
                {Number(stats.bestMonth.revenue || 0).toLocaleString()}
              </div>
            </div>
          )}
        </div>

        {/* Monthly table */}
        {statsLoading && <p style={{ marginTop: 10 }}>Loading stats...</p>}

        {!statsLoading && stats?.monthly && (
          <div style={{ marginTop: 14 }}>
            <table border="1" cellPadding="8" style={{ width: "100%", textAlign: "left" }}>
              <thead>
                <tr>
                  <th>Month</th>
                  <th>Revenue</th>
                  <th>Sales</th>
                  <th>Avg Sale Value</th>
                </tr>
              </thead>
              <tbody>
                {stats.monthly.map((m) => (
                  <tr key={m.month}>
                    <td>{monthName(m.month)}</td>
                    <td>Rs. {Number(m.revenue || 0).toLocaleString()}</td>
                    <td>{Number(m.count || 0)}</td>
                    <td>Rs. {Number(m.avgSaleValue || 0).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Sales List */}
      <table border="1" cellPadding="10" style={{ width: "100%", marginTop: 14, textAlign: "left" }}>
        <thead>
          <tr>
            <th>Vehicle</th>
            <th>Deal</th>
            <th>Payment</th>
            <th>Final Price</th>
            <th>Paid</th>
            <th>Date</th>
            <th style={{ width: 230 }}>Actions</th>
          </tr>
        </thead>

        <tbody>
          {loading && (
            <tr>
              <td colSpan="7">Loading sales...</td>
            </tr>
          )}

          {!loading &&
            sales.map((s) => (
              <tr key={s._id}>
                <td>
                  {s.vehicle?.brand
                    ? `${s.vehicle.brand} ${s.vehicle.model || s.vehicle.type || ""}`
                    : "-"}
                </td>
                <td>{s.dealStatus || "-"}</td>
                <td>{s.paymentStatus || "-"}</td>
                <td>{s.finalPrice ? `Rs. ${Number(s.finalPrice).toLocaleString()}` : "-"}</td>
                <td>{`Rs. ${Number(s.paidAmount || 0).toLocaleString()}`}</td>
                <td>{s.createdAt ? new Date(s.createdAt).toLocaleDateString() : "-"}</td>
                <td>
                  {canManage ? (
                    <>
                      <button onClick={() => navigate(`/sales/edit-payment/${s._id}`)}>
                        Edit Payment
                      </button>
                      <button style={{ marginLeft: 6 }} onClick={() => onDelete(s._id)}>
                        Delete
                      </button>
                    </>
                  ) : (
                    <span>-</span>
                  )}
                </td>
              </tr>
            ))}

          {!loading && sales.length === 0 && (
            <tr>
              <td colSpan="7">No sales found</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}
